+// Per-thread observability counter for the recursive-CTE direct SUM consumer fast
+// path. Tests assert both `== 0` (fast path declined) and `> 0` (fast path taken);
+// those assertions race on a shared process-global atomic because unrelated tests
+// running in parallel can legitimately fire the same hook. A thread-local counter
+// scopes each observation to the asserting thread, eliminating the race without
+// changing production behaviour (this value is only read by tests).
+thread_local! {
+    static FSQLITE_RECURSIVE_CTE_DIRECT_SUM_CONSUMER_HITS_TLS: std::cell::Cell<u64> =
+        const { std::cell::Cell::new(0) };
+}
+
+/// Zero-sized, `AtomicU64`-shaped handle for the thread-local recursive-CTE direct
+/// SUM consumer counter. Kept call-compatible with the previous `AtomicU64` API so
+/// existing call sites (production instrumentation + unit tests) read unchanged.
+struct RecursiveCteDirectSumConsumerHits;
+
+impl RecursiveCteDirectSumConsumerHits {
+    fn fetch_add(&self, v: u64, _order: AtomicOrdering) -> u64 {
+        FSQLITE_RECURSIVE_CTE_DIRECT_SUM_CONSUMER_HITS_TLS.with(|c| {
+            let prev = c.get();
+            c.set(prev.wrapping_add(v));
+            prev
+        })
+    }
+
+    // `store` and `load` are only consumed by `#[cfg(test)]` assertions, but the
+    // handle is defined at module scope so they're visible regardless of cfg. The
+    // allow keeps the shape call-compatible with the prior `AtomicU64` without
+    // pulling the whole impl behind `#[cfg(test)]`.
+    #[allow(dead_code)]
+    fn store(&self, v: u64, _order: AtomicOrdering) {
+        FSQLITE_RECURSIVE_CTE_DIRECT_SUM_CONSUMER_HITS_TLS.with(|c| c.set(v));
+    }
+
+    #[allow(dead_code)]
+    fn load(&self, _order: AtomicOrdering) -> u64 {
+        FSQLITE_RECURSIVE_CTE_DIRECT_SUM_CONSUMER_HITS_TLS.with(std::cell::Cell::get)
+    }
+}
+
+#[allow(non_upper_case_globals)]
+const FSQLITE_RECURSIVE_CTE_DIRECT_SUM_CONSUMER_HITS: RecursiveCteDirectSumConsumerHits =
+    RecursiveCteDirectSumConsumerHits;
